<script setup lang="ts">
  import { Tag } from '@/models/tag';
  import { UnwrapRef } from 'vue';

  const { tag } = defineProps<{
    tag: UnwrapRef<Tag>;
    showTags?: boolean;
  }>();

  const storeTask = await useStoreTask();
</script>

<template>
  <div class="flex flex-col mt-1 gap-2">
    <Toggle
      v-for="task in storeTask.tasks"
      :key="task.id"
      :model-value="task.data.tags.includes(tag.id)"
      :label="task.title"
      flat
      :class="[
        '!justify-start',
        'h-auto',
        'text-left',
        { 'line-through': task.isDone, 'opacity-50': !task.isAvailable },
      ]"
      @update:model-value="
        v => {
          if (v) {
            task.tagAdd(tag);
          } else {
            task.tagRemove(tag);
          }
        }
      "
    />
  </div>
</template>

<style lang="scss"></style>
