<script setup lang="ts">
  import { Tag } from '~~/models/tag';

  const route = useRoute();
  const router = useRouter();
  const storeTag = await useStoreTag();

  let showHidden = $ref(false);
  let tag = $ref<null | Tag>(null);
  const id = $computed(() => route.params.id as string);
  watchEffect(async () => tag = await tagGet(id));

  const STATE = {
    VIEW: 1,
    EDIT: 2,
    AVAILABILITY: 3,
    RELATIONS: 4,
    TASKS: 5,
  };

  let state = $ref(STATE.VIEW);

  let stateView = $computed(() => state === STATE.VIEW);

  let stateEdit = $computed({
    get() {
      return state === STATE.EDIT;
    },
    set(value) {
      state = value ? STATE.EDIT : STATE.VIEW;
    },
  });

  let stateAvailability = $computed({
    get() {
      return state === STATE.AVAILABILITY;
    },
    set(value) {
      state = value ? STATE.AVAILABILITY : STATE.VIEW;
    },
  });

  async function tagDelete() {
    const { value: isConfirmed } = await Dialog.confirm({
      message: 'Are you sure you want to delete this tag?',
    });
    if (!isConfirmed) return;
    await storeTag.tagDelete(id);
    router.push({ path: '/tag/list' });
  }

  const storeTask = await useStoreTask();
  let newTaskName = $ref('');

  async function taskSave() {
    const task = Task.fromData({ title: newTaskName });
    await storeTask.taskSave(task);
    tag && task.tagAdd(tag);
    newTaskName = '';
    return task;
  }

  async function taskSaveAndEdit() {
    const task = await taskSave();
    router.push({ path: `/task/${task.id}` });
  }

  function taskDiscard() {
    newTaskName = '';
  }

  const isTaskEditInProgress = $computed(() => !!newTaskName);

  const showEye = $computed(
    () =>
      tag &&
      tag.isAvailable &&
      tag.tasks.length > tag.tasks.filter(t => t.isAvailable).length,
  );
</script>

<template>
  <Loading v-if="!tag" />
  <NuxtLayout
    v-else
    name="common"
  >
    <template #header>
      <Button
        icon="fa6-solid:trash"
        flat
        @click="tagDelete"
      />
      <div class="flex-grow"></div>
      <div
        :class="[
          'pr-3',
          'flex',
          'flex-col',
          'items-end',
          'gap-1',
          'transition-opacity',
          'duration-300',
          { 'opacity-50': !tag.isAvailable },
        ]"
      >
        <div class="text-primary">
          {{ tag.name }}
        </div>
        <Progress
          v-slot="{ total, done }"
          :total="tag.tasksTotal"
          :done="tag.tasksDone"
          class="lowercase"
        >
          {{ done }} / {{ total }} tasks
        </Progress>
        <Availability
          :ms-switch-after="tag.tsSwitchAt"
          :is-available="tag.isAvailable"
        />
      </div>
    </template>
    <template #default>
      <div
        :key="state"
        class="px-4 py-1"
      >
        <TagTasksEdit
          v-if="stateEdit"
          :tag="tag"
        />
        <TagTasksView
          v-if="stateView"
          :tag="tag"
          :show-hidden="showHidden || !tag.isAvailable"
        />
        <EditorAvailability
          v-if="stateAvailability"
          key="availability"
          :available="tag"
        />
      </div>
    </template>
    <template #footer>
      <Button
        v-if="isTaskEditInProgress"
        key="task-discard"
        icon="fa6-solid:xmark"
        flat
        @click="taskDiscard"
      />
      <template v-else>
        <Toggle
          v-if="showEye"
          key="show-hidden"
          v-model="showHidden"
          :class="[showHidden && 'text-primary']"
          flat
        >
          <Icon name="fa6-solid:eye" />
        </Toggle>
      </template>
      <Input
        v-if="stateEdit"
        key="tag-name"
        v-model="tag.name"
        flat
        class="flex-grow"
      />
      <Input
        v-else
        key="task-name"
        v-model="newTaskName"
        class="flex-grow"
        placeholder="New task"
        flat
      />
      <template v-if="isTaskEditInProgress">
        <Button
          key="task-save-and-edit"
          flat
          icon="fluent:save-edit-24-filled"
          @click="taskSaveAndEdit"
        />
        <Button
          key="task-save"
          flat
          icon="fluent:save-24-filled"
          @click="taskSave"
        />
      </template>
      <template v-else>
        <Toggle
          key="state-availability"
          v-model="stateAvailability"
          icon="mdi:calendar-clock"
          flat
        />
        <Toggle
          key="state-edit"
          v-model="stateEdit"
          icon="fa6-solid:pencil"
          flat
        />
      </template>
    </template>
  </NuxtLayout>
</template>

<style lang="scss"></style>
